import React, {useState, useRef, useEffect} from 'react';
import { Link } from 'react-router-dom';
import './NavBar.css';

const navigation = [
  { name: 'Dashboard', to: '/dashboard', current: true },
  { name: 'Inventory', to: '/inventory', current: false },
  { name: 'Orders', to: '/orders', current: false },
  { name: 'Customers', to: '/customers', current: false },
  { name: 'Suppliers', to: '/suppliers', current: false },
  { name: 'Reports', to: '/reports', current: false },
];

function IconMenu(){
  return (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M4 6h16M4 12h16M4 18h16" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function IconClose(){
  return (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M6 18L18 6M6 6l12 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function IconBell(){
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6 6 0 10-12 0v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0a3 3 0 11-6 0h6z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

export default function NavBar(){
  const [mobileOpen, setMobileOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const profileRef = useRef();

  useEffect(()=>{
    function onDoc(e){
      if(profileRef.current && !profileRef.current.contains(e.target)) setProfileOpen(false);
    }
    document.addEventListener('click', onDoc);
    return ()=>document.removeEventListener('click', onDoc);
  },[]);

  return (
    <nav className="ab-nav">
      <div className="ab-container">
        <div className="ab-left">
          <button className="ab-mobile-btn" onClick={()=>setMobileOpen(!mobileOpen)} aria-label="toggle menu">
            <span className="ab-sr">Toggle menu</span>
            {mobileOpen ? <IconClose/> : <IconMenu/>}
          </button>
          <div className="ab-brand">
            <img src="/logo.png" alt="Alok & Brother" onError={(e)=>e.target.style.display='none'} />
          </div>
        </div>

        <div className="ab-center">
          <div className={`ab-links ${mobileOpen? 'open': ''}`}>
            {navigation.map(item => (
              <Link key={item.name} to={item.to} className={`ab-link ${item.current? 'current':''}`} onClick={()=>setMobileOpen(false)}>
                {item.name}
              </Link>
            ))}
            <Link to="/login" className="ab-link login" onClick={()=>setMobileOpen(false)}>Login</Link>
            <Link to="/signup" className="ab-link signup" onClick={()=>setMobileOpen(false)}>Sign Up</Link>
          </div>
        </div>

        <div className="ab-right">
          <button className="ab-icon" aria-label="notifications"><IconBell/></button>
          <div className="ab-profile" ref={profileRef}>
            <button className="ab-profile-btn" onClick={()=>setProfileOpen(!profileOpen)}>
              <img src="/profile-placeholder.png" alt="" onError={(e)=>{e.target.src='/avatar.png'}} />
            </button>
            {profileOpen && (
              <div className="ab-profile-menu">
                <Link to="/profile" className="ab-profile-item">Your profile</Link>
                <a href="#" className="ab-profile-item">Settings</a>
                <a href="#" className="ab-profile-item">Sign out</a>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}
